#include <CL/cl.h>

#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 508
#endif

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    bool is_leaf;
    int num_keys;
} knode;

kernel void findK(long maxheight,
                  const knode *knodes,
                  long knodes_elem,
                  const record *records,
                  long *currKnode,
                  long *offset,
                  const int *keys,
                  record *ans)
{
    int bid = get_global_id(0) / get_local_size(0);
    int thid = get_global_id(0) % get_local_size(0);
    int threadsPerBlock = get_local_size(0);

    if (bid >= get_global_size(0) / get_local_size(0))
        return;

    int i;

    for (i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[currKnode[bid]].keys[thid] <= keys[bid]) && 
                (knodes[currKnode[bid]].keys[thid + 1] > keys[bid])) {
                if (knodes[currKnode[bid]].indices[thid] < knodes_elem) {
                    offset[bid] = knodes[currKnode[bid]].indices[thid];
                }
            }
        }

        if (thid == 0) {
            currKnode[bid] = offset[bid];
        }
    }

    if (thid < threadsPerBlock) {
        if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
            ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
        }
    }
}

